import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./Login.css";

const Login = ({ onLoginSuccess }) => {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [error, setError] = useState("");
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError("");
        setLoading(true);

        try {
            const res = await fetch("http://localhost:5000/login", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ email, password })
            });

            const data = await res.json();

            if (!res.ok) {
                setError(data.message || "Đăng nhập thất bại!");
                setLoading(false);
                return;
            }

            // ⭐ Lưu đúng key "token" và "user" để App.js đọc được
            localStorage.setItem("token", data.token);
            localStorage.setItem("user", JSON.stringify(data.user));

            if (onLoginSuccess) onLoginSuccess(data.user);
            navigate("/", { replace: true });

        } catch (err) {
            setError("Không thể kết nối đến server!");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={styles.page}>
            <div style={styles.card}>
                <h2 style={styles.title}>E-Tech Admin</h2>
                <p style={styles.sub}>Đăng nhập hệ thống quản trị</p>

                <form onSubmit={handleSubmit} style={styles.form}>
                    <div style={styles.group}>
                        <label style={styles.label}>Email</label>
                        <input style={styles.input} type="email" value={email} required
                            placeholder="admin@etech.com"
                            onChange={e => setEmail(e.target.value)} />
                    </div>
                    <div style={styles.group}>
                        <label style={styles.label}>Mật khẩu</label>
                        <input style={styles.input} type="password" value={password} required
                            placeholder="••••••••"
                            onChange={e => setPassword(e.target.value)} />
                    </div>

                    {error && <p style={styles.error}>⚠ {error}</p>}

                    <button type="submit" style={styles.btn} disabled={loading}>
                        {loading ? "Đang đăng nhập..." : "Đăng nhập"}
                    </button>
                </form>
            </div>
        </div>
    );
};

